INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6011, 11, 6, 0.8, 1, 6, 0, 0, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 129911, 0);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6012, 91, "", "", "", 6, "", "", "", 0, "");
