INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6015, 21, 0, "", 0, 6, "", "", "vo_minigame_1013_top_talk_6_002", "vo_minigame_1013", "");
